patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..6c237cee2110 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,41 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq (and (add X, -1), ~K), 0) -> (icmp eq (and X, ~K), 1)
+  // where K is a power of 2.
+  // If X is known to have no bits set except possibly bit 0 and bit k,
+  // we can simplify to (icmp ne (and X, 1), 0).
+  {
+    Value *A;
+    const APInt *Msk;
+    if (match(And, m_And(m_OneUse(m_Add(m_Value(A), m_AllOnes())),
+                         m_APInt(Msk))) &&
+        C.isZero() && Pred == CmpInst::ICMP_EQ) {
+      // Check if Msk = ~K where K is a power of 2
+      APInt K = ~(*Msk);
+      if (K.isPowerOf2() && !K.isZero()) {
+        unsigned k = K.exactLogBase2();
+        KnownBits Known = computeKnownBits(A, &Cmp);
+        unsigned BitWidth = A->getType()->getScalarSizeInBits();
+        // Check if all bits except 0 and k are known zero
+        APInt ExpectedZero = APInt::getAllOnes(BitWidth);
+        ExpectedZero.clearBit(0);
+        ExpectedZero.clearBit(k);
+        if ((Known.Zero & ExpectedZero) == ExpectedZero) {
+          // X & 1 != 0
+          Value *Mask1 =
+              Builder.CreateAnd(A, ConstantInt::get(A->getType(), 1));
+          return new ICmpInst(ICmpInst::ICMP_NE, Mask1,
+                              ConstantInt::getNullValue(A->getType()));
+        }
+        // ((X-1) & ~K) == 0 -> (X & ~K) == 1
+        Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), *Msk));
+        return new ICmpInst(Pred, MaskA,
+                            ConstantInt::get(MaskA->getType(), 1));
+      }
+    }
+  }
+
   return nullptr;
 }

