Okay, I can use `~(*Msk)` to get the complement, then check if it's a power of 2.

Now let me write the code. I need to add a new pattern in `foldICmpAndConstant`. Let me formulate the implementation:

```cpp
  // (icmp eq (and (add X, -1), ~K), 0) -> (icmp eq (and X, ~K), 1)
  // where K is a power of 2. This is always valid.
  // If X is known to have no bits set in positions [1, k-1] and [k+1, ∞),
  // we can further simplify to (icmp ne (and X, 1), 0).
  {
    Value *A;
    const APInt *Msk;
    if (match(And, m_And(m_OneUse(m_Add(m_Value(A), m_AllOnes())),
                         m_APInt(Msk))) &&
        C.isZero() && Pred == CmpInst::ICMP_EQ) {
      // Check if Msk = ~K where K is a power of 2
      APInt K = ~(*Msk);
      if (K.isPowerOf2() && K != 0) {
        // Check if we can simplify further to just check bit 0
        unsigned k = K.exactLogBase2();
        // Check if X has no bits set in positions [1, k-1] and [k+1, ∞)
        // i.e., X's known bits show these are zero
        KnownBits Known = computeKnownBits(A, &Cmp);
        unsigned BitWidth = A->getType()->getScalarSizeInBits();
        APInt ExpectedZero = APInt::getAllOnes(BitWidth);
        // Allow bit 0 and bit k to be set
